-- ----------------------------------------------------------------------------
-- vw_users: Bank employees: relationship managers, underwriters, branch bankers, and admins. Used for portfolio assignment, audit trails, and segregation-of-duties enforcement.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_users CASCADE;
CREATE VIEW vw_users WITH (security_invoker = ON) AS
SELECT
  t.users_id,                                                                   -- Primary key (auto-synthesized: Users had no field named 'Id' or ending in 'Id').
  calc_users_name(t.users_id) AS name,                                          -- Kebab-cased compound primary key derived from FullName.
  t.full_name,                                                                  -- Display label of the bank employee.
  t.role,                                                                       -- Role discriminator: RM, Underwriter, BranchBanker, or Admin.
  t.email,                                                                      -- Bank email used for SSO and notifications.
  calc_users_is_rm(t.users_id) AS is_rm,                                        -- True when Role = 'RM' (relationship manager).
  calc_users_is_underwriter(t.users_id) AS is_underwriter,                      -- True when Role = 'Underwriter'.
  calc_users_is_branch_banker(t.users_id) AS is_branch_banker,                  -- True when Role = 'BranchBanker'.
  calc_users_is_admin(t.users_id) AS is_admin,                                  -- True when Role = 'Admin'.
  calc_users_count_of_portfolio_businesses(t.users_id) AS count_of_portfolio_businesses,-- Number of Businesses whose RelationshipManager is this user.
  calc_users_count_of_originated_loans(t.users_id) AS count_of_originated_loans,-- Number of Loans this user originated as the RM of record.
  calc_users_count_of_underwritten_loans(t.users_id) AS count_of_underwritten_loans-- Number of Loans this user underwrote.
FROM users t;

-- ----------------------------------------------------------------------------
-- vw_businesses: Small-business customers (and prospects) of the bank. Central entity: BeneficialOwners, Contacts, Accounts, Loans, Documents, and Interactions all hang off a Business. BusinessProfile information (legal name, structure, NAICS code) lives directly on this table.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_businesses CASCADE;
CREATE VIEW vw_businesses WITH (security_invoker = ON) AS
SELECT
  t.businesses_id,                                                              -- Primary key (auto-synthesized: Businesses had no field named 'Id' or ending in 'Id').
  calc_businesses_name(t.businesses_id) AS name,                                -- Kebab-cased compound PK derived from LegalName (punctuation stripped).
  t.legal_name,                                                                 -- Registered legal name of the business.
  t.business_structure,                                                         -- Entity structure: LLC, C-Corp, S-Corp, Partnership, Sole Proprietor, etc.
  t.naics_code,                                                                 -- North American Industry Classification System code for the business.
  t.naics_description,                                                          -- Human-readable label for the NAICS code.
  t.annual_revenue_usd,                                                         -- Most-recent annual revenue, USD.
  t.status,                                                                     -- Lifecycle status: Prospect, Customer, or Closed.
  t.onboarded_at,                                                               -- Date onboarding completed (KYB cleared, first account opened).
  t.relationship_manager,                                                       -- FK to Users: the RM who owns this business relationship (the SinglePointOfContact).
  t.referral_source,                                                            -- Optional FK to another Business that referred this prospect/customer in.
  calc_businesses_relationship_manager_label(t.businesses_id) AS relationship_manager_label,-- Display label of the assigned RM, pulled from Users.
  calc_businesses_is_customer(t.businesses_id) AS is_customer,                  -- True when Status = 'Customer'.
  calc_businesses_is_prospect(t.businesses_id) AS is_prospect,                  -- True when Status = 'Prospect'.
  calc_businesses_was_referred(t.businesses_id) AS was_referred,                -- True when this business was referred in by another business.
  calc_businesses_count_of_beneficial_owners(t.businesses_id) AS count_of_beneficial_owners,-- Number of BeneficialOwner rows attached.
  calc_businesses_count_of_contacts(t.businesses_id) AS count_of_contacts,      -- Number of Contact rows attached.
  calc_businesses_count_of_accounts(t.businesses_id) AS count_of_accounts,      -- Number of Account rows attached.
  calc_businesses_count_of_loans(t.businesses_id) AS count_of_loans,            -- Number of Loan rows attached.
  calc_businesses_count_of_interactions(t.businesses_id) AS count_of_interactions,-- Number of Interaction rows attached (the activity feed).
  calc_businesses_count_of_documents(t.businesses_id) AS count_of_documents,    -- Number of Documents attached directly to this Business.
  calc_businesses_total_deposit_balance_usd(t.businesses_id) AS total_deposit_balance_usd,-- Sum of CurrentBalanceUsd across this Business's Accounts.
  calc_businesses_total_loan_principal_usd(t.businesses_id) AS total_loan_principal_usd,-- Sum of PrincipalUsd across this Business's Loans.
  calc_businesses_count_of_classified_loans(t.businesses_id) AS count_of_classified_loans,-- Number of Loans on this Business whose risk grade is substandard or worse (>=7).
  calc_businesses_has_classified_loan(t.businesses_id) AS has_classified_loan,  -- True when at least one loan on this Business is a classified asset.
  calc_businesses_beneficial_owners_at_cdd_threshold(t.businesses_id) AS beneficial_owners_at_cdd_threshold,-- Count of BeneficialOwners meeting FinCEN's 25% threshold or marked as the control person.
  calc_businesses_meets_cdd_rule(t.businesses_id) AS meets_cdd_rule,            -- True when CDD beneficial-ownership collection is satisfied: at least one owner crosses the 25% threshold, or a control person is designated.
  calc_businesses_portfolio_priority(t.businesses_id) AS portfolio_priority     -- Higher-order: portfolio-management priority bucket for this business. 'High' when classified loan present, 'Medium' when CDD or onboarding incomplete or no loans yet, otherwise 'Low'.
FROM businesses t;

-- ----------------------------------------------------------------------------
-- vw_beneficial_owners: Individuals owning 25%+ of a Business plus designated control persons, per FinCEN's CDD rule. PII (SSN, DOB, address) is stored encrypted at rest via field-level encryption.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_beneficial_owners CASCADE;
CREATE VIEW vw_beneficial_owners WITH (security_invoker = ON) AS
SELECT
  t.beneficial_owners_id,                                                       -- Primary key (auto-synthesized: BeneficialOwners had no field named 'Id' or ending in 'Id').
  calc_beneficial_owners_name(t.beneficial_owners_id) AS name,                  -- Kebab-cased compound PK: {Business}-{FullName slug}.
  t.business,                                                                   -- FK to the parent Business.
  t.full_name,                                                                  -- Owner's full legal name.
  t.date_of_birth_encrypted,                                                    -- Encrypted date of birth (PII, FieldLevelEncryption).
  t.ssn_encrypted,                                                              -- Encrypted Social Security Number (PII, FieldLevelEncryption).
  t.address_encrypted,                                                          -- Encrypted home address (PII, FieldLevelEncryption).
  t.ownership_percentage,                                                       -- Percent of the Business owned by this individual (0-100).
  t.is_control_person,                                                          -- True when this individual is the designated control person per CDD (one is required when no owner crosses 25%).
  calc_beneficial_owners_business_label(t.beneficial_owners_id) AS business_label,-- Display label of the parent Business.
  calc_beneficial_owners_meets25_percent_threshold(t.beneficial_owners_id) AS meets25_percent_threshold,-- True when OwnershipPercentage >= 25.
  calc_beneficial_owners_meets_cdd_threshold(t.beneficial_owners_id) AS meets_cdd_threshold-- True when this row counts toward CDD compliance: meets 25% OR is the control person.
FROM beneficial_owners t;

-- ----------------------------------------------------------------------------
-- vw_contacts: Non-owner individuals associated with a Business: officers, AP clerks, authorized signers, additional points of contact. Distinct from BeneficialOwners (which carries PII/CDD weight).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_contacts CASCADE;
CREATE VIEW vw_contacts WITH (security_invoker = ON) AS
SELECT
  t.contacts_id,                                                                -- Primary key (auto-synthesized: Contacts had no field named 'Id' or ending in 'Id').
  calc_contacts_name(t.contacts_id) AS name,                                    -- Kebab-cased compound PK: {Business}-{FullName slug}-{Title slug}.
  t.business,                                                                   -- FK to the parent Business.
  t.full_name,                                                                  -- Contact's full name.
  t.title,                                                                      -- Job title at the business (CEO, CFO, AP Clerk, etc.).
  t.email,                                                                      -- Contact email.
  t.phone,                                                                      -- Contact phone.
  t.contact_type,                                                               -- Discriminator: Officer, APClerk, AuthorizedSigner, Other.
  t.is_authorized_signer,                                                       -- True when this contact can sign on the business's accounts.
  calc_contacts_business_label(t.contacts_id) AS business_label,                -- Display label of the parent Business.
  calc_contacts_is_officer(t.contacts_id) AS is_officer,                        -- True when ContactType = 'Officer'.
  calc_contacts_is_ap_clerk(t.contacts_id) AS is_ap_clerk                       -- True when ContactType = 'APClerk'.
FROM contacts t;

-- ----------------------------------------------------------------------------
-- vw_accounts: Deposit accounts the Business holds at the bank (checking, savings, money market). Balances feed GlobalCashFlow during credit analysis. TreasuryServices enrollment flags (ACH, Wire, Card) are stored per-account.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_accounts CASCADE;
CREATE VIEW vw_accounts WITH (security_invoker = ON) AS
SELECT
  t.accounts_id,                                                                -- Primary key (auto-synthesized: Accounts had no field named 'Id' or ending in 'Id').
  calc_accounts_name(t.accounts_id) AS name,                                    -- Kebab-cased compound PK: {Business}-{AccountType}-{Last4}.
  t.business,                                                                   -- FK to the parent Business.
  t.account_type,                                                               -- Checking, Savings, MoneyMarket, etc.
  t.account_number_last4,                                                       -- Last 4 digits of the account number for display.
  t.current_balance_usd,                                                        -- Current balance in USD; sourced from CoreBanking.
  t.has_ach,                                                                    -- ACH treasury service enrolled on this account.
  t.has_wire,                                                                   -- Wire transfer treasury service enrolled on this account.
  t.has_card,                                                                   -- Business card product issued against this account.
  t.opened_at,                                                                  -- Date the account was opened.
  calc_accounts_business_label(t.accounts_id) AS business_label,                -- Display label of the parent Business.
  calc_accounts_treasury_service_count(t.accounts_id) AS treasury_service_count,-- Number of treasury services enrolled on this account.
  calc_accounts_has_any_treasury_service(t.accounts_id) AS has_any_treasury_service-- True when at least one treasury service is enrolled.
FROM accounts t;

-- ----------------------------------------------------------------------------
-- vw_loans: Credit facilities extended to a Business, tracked from inquiry through funding, servicing, and payoff. RiskRating is denormalized here for fast reads; every change is captured in RiskRatingHistory.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_loans CASCADE;
CREATE VIEW vw_loans WITH (security_invoker = ON) AS
SELECT
  t.loans_id,                                                                   -- Primary key (auto-synthesized: Loans had no field named 'Id' or ending in 'Id').
  calc_loans_name(t.loans_id) AS name,                                          -- Kebab-cased PK derived from LoanNumber (e.g. 'L-0051' -> 'l-0051').
  t.loan_number,                                                                -- Bank-assigned loan number (e.g. 'L-0051').
  t.business,                                                                   -- FK to the borrower Business.
  t.originating_rm,                                                             -- FK to Users: the RM who originated this loan.
  t.underwriter,                                                                -- FK to Users: the underwriter who underwrote this loan.
  t.loan_purpose,                                                               -- Equipment, CRE, LOC, WorkingCapital, etc.
  t.principal_usd,                                                              -- Loan principal at origination, USD.
  t.rate_pct,                                                                   -- Interest rate, percent (e.g. 7.25).
  t.term_months,                                                                -- Loan term in months.
  t.underwriting_stage,                                                         -- Current pipeline stage: Inquiry, PreQualification, Application, KYBAndBureauPull, Packaging, CreditAnalysis, CommitteeApproval, ClosingPrep, Signing, Funded.
  t.risk_rating,                                                                -- Current risk grade (1=Pass strongest ... 7=Substandard ... 9=Loss). Denormalized; every change is captured in RiskRatingHistory.
  t.risk_rating_label,                                                          -- Human-readable label for the current risk grade.
  t.dscr,                                                                       -- Most recent debt service coverage ratio.
  t.ltv,                                                                        -- Most recent loan-to-value ratio (0-1); null for unsecured loans.
  t.global_cash_flow_usd,                                                       -- Most recent global cash flow figure across business, owners, and affiliates.
  t.originated_at,                                                              -- Date the application was created.
  t.funded_at,                                                                  -- Date the loan funded; null until funding completes.
  calc_loans_business_label(t.loans_id) AS business_label,                      -- Display label of the borrower Business.
  calc_loans_business_naics_code(t.loans_id) AS business_naics_code,            -- NAICS code of the borrower Business (concentration analytics).
  calc_loans_originating_rm_label(t.loans_id) AS originating_rm_label,          -- Display label of the originating RM.
  calc_loans_underwriter_label(t.loans_id) AS underwriter_label,                -- True if the underwriter is an admin.
  calc_loans_is_funded(t.loans_id) AS is_funded,                                -- True when UnderwritingStage = 'Funded'.
  calc_loans_is_classified_asset(t.loans_id) AS is_classified_asset,            -- True when RiskRating is substandard (7) or worse.
  calc_loans_dscr_in_band(t.loans_id) AS dscr_in_band,                          -- True when DSCR meets or exceeds the 1.20 minimum band.
  calc_loans_ltv_in_band(t.loans_id) AS ltv_in_band,                            -- True when LTV is at or below 0.80, or null (unsecured).
  calc_loans_segregation_of_duties_ok(t.loans_id) AS segregation_of_duties_ok,  -- True when the originating RM and the underwriter are different Users (segregation-of-duties check).
  calc_loans_count_of_covenants(t.loans_id) AS count_of_covenants,              -- Number of Covenants attached to this loan.
  calc_loans_count_of_breached_covenants(t.loans_id) AS count_of_breached_covenants,-- Number of Covenants currently in Breached status on this loan.
  calc_loans_count_of_risk_rating_history(t.loans_id) AS count_of_risk_rating_history,-- Number of RiskRatingHistory rows for this loan.
  calc_loans_count_of_documents(t.loans_id) AS count_of_documents,              -- Number of Documents attached directly to this Loan.
  calc_loans_has_breached_covenant(t.loans_id) AS has_breached_covenant,        -- True when at least one covenant is in breach.
  calc_loans_on_watchlist(t.loans_id) AS on_watchlist,                          -- Higher-order: on the watchlist when the loan is a classified asset OR has any breached covenant.
  calc_loans_health_score(t.loans_id) AS health_score                           -- Higher-order composite health score (0-4): +1 for DscrInBand, +1 for LtvInBand, +1 for NOT IsClassifiedAsset, +1 for NOT HasBreachedCovenant.
FROM loans t;

-- ----------------------------------------------------------------------------
-- vw_covenants: Conditions attached to a Loan that must be tested on a recurring schedule (e.g. minimum DSCR each quarter). CovenantMonitoring runs the tickler calendar ahead of NextTestDate; breaches surface as SystemEvent Interactions.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_covenants CASCADE;
CREATE VIEW vw_covenants WITH (security_invoker = ON) AS
SELECT
  t.covenants_id,                                                               -- Primary key (auto-synthesized: Covenants had no field named 'Id' or ending in 'Id').
  calc_covenants_name(t.covenants_id) AS name,                                  -- Kebab-cased compound PK: {Loan}-{CovenantType slug}.
  t.loan,                                                                       -- FK to the parent Loan.
  t.covenant_type,                                                              -- MinDSCR, MaxLeverage, ReportingFinancials, etc.
  t.threshold_value,                                                            -- Numeric threshold for the test (e.g. 1.20 for MinDSCR); null for non-numeric covenants.
  t.test_frequency,                                                             -- Quarterly, Annual, Monthly, etc.
  t.next_test_date,                                                             -- Date of the next scheduled covenant test.
  t.status,                                                                     -- Active, Breached, Waived, Cured, Closed.
  t.current_waiver_through,                                                     -- Date through which an active CovenantWaiver is in effect; null when no active waiver.
  calc_covenants_loan_label(t.covenants_id) AS loan_label,                      -- Display label of the parent Loan.
  calc_covenants_loan_business(t.covenants_id) AS loan_business,                -- Business of the parent Loan (chained lookup).
  calc_covenants_is_breached(t.covenants_id) AS is_breached,                    -- True when Status = 'Breached'.
  calc_covenants_has_active_waiver(t.covenants_id) AS has_active_waiver         -- True when CurrentWaiverThrough is set (waiver is on file).
FROM covenants t;

-- ----------------------------------------------------------------------------
-- vw_risk_rating_history: Time-series of risk-grade changes on a Loan. Regulators audit rating drift, so every migration is captured here. AnnualReview also writes a row even when the grade is reaffirmed unchanged.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_risk_rating_history CASCADE;
CREATE VIEW vw_risk_rating_history WITH (security_invoker = ON) AS
SELECT
  t.risk_rating_history_id,                                                     -- Primary key (auto-synthesized: RiskRatingHistory had no field named 'Id' or ending in 'Id').
  calc_risk_rating_history_name(t.risk_rating_history_id) AS name,              -- Kebab-cased compound PK: {Loan}-{EffectiveDate}-grade-{NewGrade}.
  t.loan,                                                                       -- FK to the Loan whose grade changed.
  t.changed_by_user,                                                            -- FK to Users: who recorded the migration.
  t.effective_date,                                                             -- Date the new grade takes effect.
  t.prior_grade,                                                                -- Grade before this change; null on initial rating.
  t.new_grade,                                                                  -- Grade after this change.
  t.reason,                                                                     -- Free-text justification for the migration.
  calc_risk_rating_history_loan_label(t.risk_rating_history_id) AS loan_label,  -- Display label of the parent Loan.
  calc_risk_rating_history_changed_by_user_label(t.risk_rating_history_id) AS changed_by_user_label,-- Display label of the user who recorded the change.
  calc_risk_rating_history_grade_delta(t.risk_rating_history_id) AS grade_delta,-- NewGrade - PriorGrade (positive = downgrade in this scale); equals 0 on initial rating.
  calc_risk_rating_history_is_downgrade(t.risk_rating_history_id) AS is_downgrade,-- True when the migration represents a downgrade (higher grade number = worse risk).
  calc_risk_rating_history_is_initial_rating(t.risk_rating_history_id) AS is_initial_rating,-- True when this is the loan's first rating row (no PriorGrade).
  calc_risk_rating_history_crossed_classified_threshold(t.risk_rating_history_id) AS crossed_classified_threshold-- Higher-order: true when this migration is the moment a loan crossed from non-classified to classified (PriorGrade < 7 and NewGrade >= 7).
FROM risk_rating_history t;

-- ----------------------------------------------------------------------------
-- vw_documents: Files in the DocumentVault. A document attaches to either a Business (tax returns, formation docs) or a Loan (note, security agreement, appraisal). Both FKs are nullable so a document can hang off the appropriate parent.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_documents CASCADE;
CREATE VIEW vw_documents WITH (security_invoker = ON) AS
SELECT
  t.documents_id,                                                               -- Primary key (auto-synthesized: Documents had no field named 'Id' or ending in 'Id').
  calc_documents_name(t.documents_id) AS name,                                  -- Kebab-cased PK derived from the filename.
  t.business,                                                                   -- Optional FK to a Business (nullable for loan-only docs).
  t.loan,                                                                       -- Optional FK to a Loan (nullable for business-only docs).
  t.uploaded_by_user,                                                           -- Optional FK to the User who uploaded (null when uploaded via the BusinessClientPortal).
  t.filename,                                                                   -- Original filename in the vault.
  t.document_type,                                                              -- TaxReturn, FormationDoc, FinancialStatement, Note, SecurityAgreement, Appraisal, etc.
  t.ocr_indexed,                                                                -- True once OCR has indexed the document into SearchAndIndexing.
  t.uploaded_via,                                                               -- Source surface: RMDashboard, BranchBankerPortal, BusinessClientPortal, AdminConsole, API.
  t.uploaded_at,                                                                -- Upload timestamp.
  calc_documents_business_label(t.documents_id) AS business_label,              -- Display label of the attached Business (if any).
  calc_documents_loan_label(t.documents_id) AS loan_label,                      -- Display label of the attached Loan (if any).
  calc_documents_uploaded_by_user_label(t.documents_id) AS uploaded_by_user_label,-- Display label of the uploader (if known).
  calc_documents_attached_to(t.documents_id) AS attached_to,                    -- Which parent this document hangs off: 'Loan', 'Business', or 'Orphan' (neither set).
  calc_documents_from_customer_portal(t.documents_id) AS from_customer_portal   -- True when uploaded by the customer themselves via the BusinessClientPortal.
FROM documents t;

-- ----------------------------------------------------------------------------
-- vw_interactions: Unified activity-log feed for a Business. An Interaction is intentionally generic: InteractionType discriminates Note, Call, Visit, Task, Meeting, or SystemEvent. Covenant breaches, document requests, and other machine actions are written as SystemEvent interactions so they appear in the same stream as human-logged activity.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_interactions CASCADE;
CREATE VIEW vw_interactions WITH (security_invoker = ON) AS
SELECT
  t.interactions_id,                                                            -- Primary key (auto-synthesized: Interactions had no field named 'Id' or ending in 'Id').
  calc_interactions_name(t.interactions_id) AS name,                            -- Kebab-cased compound PK: {Business}-{InteractionDate}-{InteractionType slug}-{Subject slug}.
  t.business,                                                                   -- FK to the parent Business.
  t."user",                                                                     -- FK to Users: who logged the interaction (null for system-generated or customer-portal-originated rows).
  t.interaction_type,                                                           -- Note, Call, Visit, Task, Meeting, or SystemEvent.
  t.subject,                                                                    -- Short subject line (used in compound PK).
  t.body,                                                                       -- Long-form body of the interaction.
  t.interaction_date,                                                           -- Date the interaction occurred or was logged.
  t.due_date,                                                                   -- For Task-type interactions: due date.
  t.source,                                                                     -- Origin surface: RMDashboard, BusinessClientPortal, BranchBankerPortal, SystemEvent.
  calc_interactions_business_label(t.interactions_id) AS business_label,        -- Display label of the parent Business.
  calc_interactions_user_label(t.interactions_id) AS user_label,                -- Display label of the logging user (if any).
  calc_interactions_is_system_event(t.interactions_id) AS is_system_event,      -- True for system-generated rows.
  calc_interactions_is_task(t.interactions_id) AS is_task,                      -- True for Task-type rows.
  calc_interactions_from_customer(t.interactions_id) AS from_customer,          -- True when sourced from the BusinessClientPortal (customer-originated).
  calc_interactions_is_covenant_event(t.interactions_id) AS is_covenant_event   -- Higher-order: true when this is a covenant-related system event (subject contains 'covenant').
FROM interactions t;

